function detectBranch(code) {
  const normalized = code.toUpperCase().trim();

  // Air Force AFSC: digit + letter + digits + letter (e.g., 1A0X1)
  if (/^\d[A-Z]\d+X?\d*$/.test(normalized)) {
    return 'air_force';
  }

  // Army MOS: 2 digits + letter (e.g., 11B, 25B)
  if (/^\d{2}[A-Z]\d?$/.test(normalized)) {
    return 'army';
  }

  // Marines MOS: 4 digits (e.g., 0311)
  if (/^\d{4}$/.test(normalized)) {
    return 'marines';
  }

  // Navy/Coast Guard: 2-3 letters (e.g., DC, IT, CTN)
  // Disambiguate by checking both crosswalks
  if (/^[A-Z]{2,4}$/.test(normalized)) {
    return 'navy_or_coastguard'; // Check both files
  }

  return 'unknown';
}
